solution_code:
#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> evens;
    for (int i = 0; i < n; ++i)
    {
        int x{};
        std::cin >> x;
        if (x % 2 == 0)
            evens.push_back(x);
    }

    if (evens.empty())
    {
        std::cout << "None\n";
    }
    else
    {
        while (!evens.empty())
        {
            std::cout << evens.back() << '\n';
            evens.pop_back();
        }
    }

    return 0;
}

