#include <iostream>
#include <vector>

enum Student { alice, bob, carol, numStudents };

int main()
{
    std::vector<int> scores(numStudents);

    for (int i = 0; i < numStudents; ++i)
        std::cin >> scores[i];

    const char* names[] = {"Alice", "Bob", "Carol"};
    for (int i = 0; i < numStudents; ++i)
        std::cout << names[i] << ": " << scores[i] << '\n';

    return 0;
}
